// frontend/src/pages/Payment.js
import React, { useContext, useState } from "react";
import { CartContext } from "../context/CartContext";
import { loadStripe } from "@stripe/stripe-js";
import { Elements, CardElement, useStripe, useElements } from "@stripe/react-stripe-js";
import "./Payment.css";

const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY);

// Checkout form component
const CheckoutForm = () => {
  const { cartItems, totalPrice } = useContext(CartContext);
  const stripe = useStripe();
  const elements = useElements();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      // Call backend to create PaymentIntent
      const res = await fetch("http://localhost:5000/api/create-payment-intent", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount: Math.round(totalPrice * 100) }), // Stripe expects cents
      });
      const data = await res.json();

      // Confirm card payment
      const cardElement = elements.getElement(CardElement);
      const confirm = await stripe.confirmCardPayment(data.clientSecret, {
        payment_method: { card: cardElement },
      });

      if (confirm.error) {
        setError(confirm.error.message);
      } else {
        setSuccess(true);
      }
    } catch (err) {
      setError("Payment failed: " + err.message);
    }

    setLoading(false);
  };

  if (success) return <h2 className="payment-success">Payment Successful! ✅</h2>;

  return (
    <form className="checkout-form" onSubmit={handleSubmit}>
      <h2>Payment Details</h2>
      <CardElement className="card-element" />
      {error && <div className="payment-error">{error}</div>}
      <button type="submit" className="payment-btn" disabled={!stripe || loading}>
        {loading ? "Processing..." : `Pay RM ${totalPrice}`}
      </button>
    </form>
  );
};

// Main Payment page
const Payment = () => {
  return (
    <div className="payment-page">
      <Elements stripe={stripePromise}>
        <CheckoutForm />
      </Elements>
    </div>
  );
};

export default Payment;
